const leads = $('Fetch Leads for Follow-up').all().map(i => i.json);
const reviews = $('Fetch 5-Star Reviews').all().map(i => i.json);

function getRandomReview() {
  if (!reviews.length) return { text: 'Professional, on-time, and our lawn has never looked better!', author_name: 'A Happy Customer' };
  return reviews[Math.floor(Math.random() * reviews.length)];
}

function truncateReview(text, maxLen) {
  if (!text) return '';
  if (text.length <= maxLen) return text;
  return text.substring(0, maxLen - 3) + '...';
}

function buildEmailHtml(options) {
  const { subject, headline, bodyHtml, reviewText, reviewerName, ctaText, ctaUrl, urgencyText, previewText } = options;
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${subject}</title></head><body style="margin:0;padding:0;background-color:#f5f5f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;"><span style="display:none;max-height:0;overflow:hidden;">${previewText || ''}</span><table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f0;"><tr><td align="center" style="padding:20px;"><table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:#2D5A27;padding:20px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:20px;font-weight:bold;">TotalGuard Yard Care</td><td align="right" style="color:#ffffff;font-size:14px;"><a href="tel:6085356057" style="color:#ffffff;text-decoration:none;">(608) 535-6057</a></td></tr><tr><td colspan="2" style="color:#C5A55A;font-size:12px;padding-top:4px;">Madison's Most Trusted Yard Care</td></tr></table></td></tr><tr><td style="padding:30px 30px 10px;"><h1 style="margin:0;color:#2D5A27;font-size:24px;">${headline}</h1></td></tr><tr><td style="padding:10px 30px 20px;color:#1a1a1a;font-size:15px;line-height:1.6;">${bodyHtml}</td></tr>${reviewText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f5f5f0;border-left:4px solid #2D5A27;padding:16px 20px;border-radius:0 6px 6px 0;"><div style="color:#C5A55A;font-size:18px;margin-bottom:8px;">&#9733;&#9733;&#9733;&#9733;&#9733;</div><div style="color:#333;font-style:italic;font-size:14px;margin-bottom:8px;">"${reviewText}"</div><div style="color:#2D5A27;font-weight:bold;font-size:13px;">-- ${reviewerName}</div><div style="color:#888;font-size:11px;">Verified Google Review</div></td></tr></table></td></tr>` : ''}<tr><td style="padding:0 30px 20px;" align="center"><table cellpadding="0" cellspacing="0"><tr><td style="background:#2D5A27;border-radius:6px;padding:14px 32px;"><a href="${ctaUrl}" style="color:#ffffff;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block;">${ctaText}</a></td></tr></table></td></tr>${urgencyText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f0f8f0;border:2px solid #2D5A27;border-radius:8px;padding:16px 20px;text-align:center;"><div style="color:#2D5A27;font-weight:bold;font-size:14px;">${urgencyText}</div></td></tr></table></td></tr>` : ''}<tr><td style="padding:0 30px 20px;text-align:center;"><div style="color:#555;font-size:13px;">Prefer to talk? <a href="tel:6085356057" style="color:#2D5A27;font-weight:bold;">(608) 535-6057</a></div></td></tr><tr><td style="padding:10px 30px;text-align:center;border-top:1px solid #eee;"><div style="color:#888;font-size:11px;">Licensed & Insured | 4.9 Google Rating | 500+ Properties | Satisfaction Guaranteed</div></td></tr><tr><td style="background:#1a1a1a;padding:24px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:14px;font-weight:bold;">TotalGuard Yard Care</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:6px;">7610 Welton Dr, Madison, WI 53711</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:4px;"><a href="tel:6085356057" style="color:#C5A55A;">(608) 535-6057</a> | <a href="mailto:totalguardllc@gmail.com" style="color:#C5A55A;">totalguardllc@gmail.com</a></td></tr><tr><td style="padding-top:10px;"><a href="https://instagram.com/totalguardyardcare" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Instagram</a> <a href="https://g.page/r/CRW5Dsg2JgwBEBM/review" style="color:#C5A55A;font-size:12px;text-decoration:none;">Google</a></td></tr><tr><td style="color:#666;font-size:10px;padding-top:10px;">Serving Madison, Middleton, Waunakee, Monona, Sun Prairie, Fitchburg, Verona, McFarland, Cottage Grove, DeForest, Oregon & Stoughton</td></tr></table></td></tr></table></td></tr></table></body></html>`;
}

const results = [];

for (const lead of leads) {
  const stage = lead.follow_up_stage || 0;
  const daysSinceCreated = Math.floor((Date.now() - new Date(lead.created_at).getTime()) / (1000 * 60 * 60 * 24));
  const name = lead.first_name || 'there';
  const service = lead.service || 'yard care';
  const review = getRandomReview();
  const reviewSnippet = truncateReview(review.text, 100);

  let touchDue = null;
  if (stage === 0 && daysSinceCreated >= 1) touchDue = 1;
  else if (stage === 1 && daysSinceCreated >= 3) touchDue = 2;
  else if (stage === 2 && daysSinceCreated >= 5) touchDue = 3;
  else if (stage === 3 && daysSinceCreated >= 7) touchDue = 4;
  else if (stage === 4 && daysSinceCreated >= 14) touchDue = 5;

  if (!touchDue) continue;

  let output = null;

  if (touchDue === 1) {
    if (!lead.phone) continue;
    output = {
      channel: 'sms',
      lead_id: lead.id,
      new_stage: 1,
      to_phone: lead.phone,
      message_body: `Hi ${name}! Just checking in about your ${service} request from TotalGuard. We'd love to get you scheduled -- reply here or call (608) 535-6057. We're ready when you are!`,
      workflow_name: 'TG-09',
      message_type: 'followup_touch1'
    };
  } else if (touchDue === 2) {
    if (!lead.email) continue;
    const html = buildEmailHtml({
      subject: `What to expect from TotalGuard, ${name}`,
      headline: "Here's What Working with TotalGuard Looks Like",
      bodyHtml: `<p>Hi ${name},</p><p>We wanted to give you a quick peek at what makes TotalGuard different:</p><ul style="color:#1a1a1a;line-height:2;"><li><strong>Free consultation</strong> -- We'll assess your property and recommend exactly what it needs</li><li><strong>Custom plan</strong> -- No cookie-cutter packages. Your lawn gets a plan built just for it</li><li><strong>Reliable crew</strong> -- Same team every visit, on time, every time</li><li><strong>Quality guarantee</strong> -- Not happy? We come back and make it right</li></ul><p>Over 500 Madison homeowners already trust us with their yards. Here's what one had to say:</p>`,
      reviewText: reviewSnippet,
      reviewerName: review.author_name || 'Verified Customer',
      ctaText: 'Schedule My Free Consultation',
      ctaUrl: 'https://tgyardcare.com/contact',
      previewText: `Here's what makes TotalGuard different, ${name}.`
    });
    output = {
      channel: 'email',
      lead_id: lead.id,
      new_stage: 2,
      to_email: lead.email,
      subject: `What to expect from TotalGuard, ${name}`,
      html_body: html,
      workflow_name: 'TG-09',
      email_type: 'followup_touch2'
    };
  } else if (touchDue === 3) {
    if (!lead.phone) continue;
    output = {
      channel: 'sms',
      lead_id: lead.id,
      new_stage: 3,
      to_phone: lead.phone,
      message_body: `Hi ${name}, ${review.author_name || 'a neighbor'} just said: "${reviewSnippet}" We'd love to earn a 5-star review from you too! Book at tgyardcare.com or call (608) 535-6057`,
      workflow_name: 'TG-09',
      message_type: 'followup_touch3'
    };
  } else if (touchDue === 4) {
    if (!lead.email) continue;
    const html = buildEmailHtml({
      subject: `Your ${service} quote is still available, ${name}`,
      headline: 'Your Quote is Still Available',
      bodyHtml: `<p>Hi ${name},</p><p>Just a heads up -- your personalized <strong>${service}</strong> quote is still available, but we can't guarantee current pricing much longer.</p><p>Spring is our busiest season, and our schedule fills up fast. Lock in your spot now and join the hundreds of Madison homeowners who trust TotalGuard.</p>`,
      reviewText: reviewSnippet,
      reviewerName: review.author_name || 'Verified Customer',
      ctaText: 'Lock In My Quote',
      ctaUrl: 'https://tgyardcare.com/contact',
      urgencyText: 'Spring schedules are filling up -- book this week to guarantee your spot!',
      previewText: `Your ${service} quote is still available, ${name}. Don't miss out.`
    });
    output = {
      channel: 'email',
      lead_id: lead.id,
      new_stage: 4,
      to_email: lead.email,
      subject: `Your ${service} quote is still available, ${name}`,
      html_body: html,
      workflow_name: 'TG-09',
      email_type: 'followup_touch4'
    };
  } else if (touchDue === 5) {
    if (!lead.email) continue;
    const html = buildEmailHtml({
      subject: `We're here when you're ready, ${name}`,
      headline: "No Pressure -- We're Here When You're Ready",
      bodyHtml: `<p>Hi ${name},</p><p>We know life gets busy, and choosing a yard care company is a big decision. No rush at all.</p><p>Whenever you're ready, TotalGuard is here with:</p><ul style="color:#1a1a1a;line-height:2;"><li>No contracts -- cancel anytime</li><li>Free property assessments</li><li>Licensed, insured, and locally owned</li><li>4.9-star Google rating from 500+ happy neighbors</li></ul><p>Save our number: <strong>(608) 535-6057</strong>. We'd love to earn your business.</p>`,
      reviewText: reviewSnippet,
      reviewerName: review.author_name || 'Verified Customer',
      ctaText: 'Get a Free Assessment',
      ctaUrl: 'https://tgyardcare.com/contact',
      previewText: `No pressure, ${name}. TotalGuard is here whenever you need us.`
    });
    output = {
      channel: 'email',
      lead_id: lead.id,
      new_stage: 5,
      to_email: lead.email,
      subject: `We're here when you're ready, ${name}`,
      html_body: html,
      workflow_name: 'TG-09',
      email_type: 'followup_touch5'
    };
  }

  if (output) results.push({ json: output });
}

return results;
